// Build identity key for Guard rate limiting
// Priority: x-api-key → X-Forwarded-For[0] → x-real-ip → 'unknown'

const headers = $('Webhook').first().json.headers;
const config = $input.first().json;

let identity;

if (config.identity_mode === 'apiKey' && headers['x-api-key']) {
  identity = headers['x-api-key'];
} else {
  const xff = headers['x-forwarded-for'];
  if (xff) {
    // Always use FIRST value (real client IP)
    identity = xff.split(',')[0].trim();
  } else {
    identity = headers['x-real-ip'] || 'unknown';
  }
}

// Format: route:identity (prevents cross-endpoint pollution)
const identityKey = `${config.route_name}:${identity}`;

return [{
  json: {
    identity_key: identityKey,
    identity: identity,
    rate_limit: config.rate_limit,
    window_sec: config.window_sec
  }
}];

